function approvalAgoLabel(d){ if(d===null||d===undefined) return null; if(d<=0) return 'hoy'; if(d===1) return 'hace 1 día'; return `hace ${d} días`; }
function approvalCard(c){
  const ago = approvalAgoLabel(c.daysWaiting);
  const sub = [];
  sub.push('📢 <@' + (c.requesterId||'') + '>');
  if (ago) sub.push('⏱ ' + ago);
  const body = c.problema && c.problema.trim()
    ? clip(c.problema, 200)
    : '_Sin descripción del problema — abrí el hilo para verlo._';
  return {
    type: 'card',
    block_id: 'apprv-' + (c.threadId||'').replace('.', '_'),
    slack_icon: { type: 'icon', name: 'rocket' },
    title:    { type: 'mrkdwn', text: '*Requerimiento esperando tu aprobación*' },
    subtitle: { type: 'mrkdwn', text: sub.join('  ·  ') || '—' },
    body:     { type: 'mrkdwn', text: body },
    actions: [{
      type: 'button',
      text: { type: 'plain_text', text: 'Ir a conversación', emoji: true },
      action_id: 'review_approval_' + (c.threadId||'').replace('.', '_'),
      url: c.threadUrl
    }]
  };
}
function approvalCarousel(title, cardsArr, emptyTxt){
  // App Home NO renderiza el bloque 'carousel' (validado en vivo 2026-06-07, H5).
  // Se apilan cards individuales, que sí renderizan en surface 'home'.
  const out = [{ type:'header', text:{ type:'plain_text', text:`${title} (${cardsArr.length})`, emoji:true } }];
  if (!cardsArr.length) { out.push(emptyNote(emptyTxt)); return out; }
  const CAP = 10;
  for (const c of cardsArr.slice(0, CAP)) out.push(approvalCard(c));
  if (cardsArr.length > CAP) out.push(emptyNote(`_…y ${cardsArr.length - CAP} más._`));
  return out;
}
function sectionCarousel(title, rowsArr, opts, emptyTxt){
  const out = [{ type:'header', text:{ type:'plain_text', text:`${title} (${rowsArr.length})`, emoji:true } }];
  if (!rowsArr.length) { out.push(emptyNote(emptyTxt)); return out; }
  const CAP = 10; // Slack: max 10 cards por carousel
  out.push(carousel(rowsArr.slice(0, CAP), opts));
  if (rowsArr.length > CAP) out.push(emptyNote(`_…y ${rowsArr.length - CAP} más._`));
  return out;
}

