// --- Aplanador ADF -> texto (Blocked cause: parrafo o tabla) ---
function adfToText(node){
  if (!node || typeof node !== 'object') return '';
  const t = node.type;
  if (t === 'text') return node.text || '';
  if (t === 'hardBreak') return ' ';
  if (t === 'mention') return (node.attrs && node.attrs.text) || '';
  if (t === 'emoji')   return (node.attrs && (node.attrs.text || node.attrs.shortName)) || '';
  if (t === 'inlineCard' || t === 'blockCard') {
    const u = node.attrs && node.attrs.url ? node.attrs.url : '';
    return u ? `[${u}]` : '[link]';
  }
  const kids = Array.isArray(node.content) ? node.content : [];
  if (t === 'tableCell' || t === 'tableHeader') return kids.map(adfToText).filter(Boolean).join(' ').trim();
  if (t === 'tableRow') return kids.map(adfToText).filter(Boolean).join(' · ');
  if (t === 'table')    return kids.map(adfToText).filter(Boolean).join('\n');
  if (t === 'paragraph') return kids.map(adfToText).join('');
  return kids.map(adfToText).filter(Boolean).join('\n');
}
function blockedCauseText(adf){
  if (!adf) return null;
  let txt = adfToText(adf).replace(/\n{2,}/g, '\n').replace(/[ \t]{2,}/g, ' ').trim();
  if (!txt) return null;
  const LIMIT = 280;
  if (txt.length > LIMIT) txt = txt.slice(0, LIMIT - 1).trimEnd() + '…';
  return txt;
}
function daysAgo(iso){ if(!iso) return null; const d=new Date(iso); if(isNaN(d)) return null; return Math.floor((Date.now()-d.getTime())/86400000); }
function agoLabel(iso){ const d=daysAgo(iso); if(d===null) return null; if(d<=0) return 'hoy'; if(d===1) return 'hace 1 día'; return `hace ${d} días`; }
function prioEmoji(p){ p=(p||'').toLowerCase(); if(p==='highest')return'🔺'; if(p==='high')return'🔴'; if(p==='medium')return'🟠'; if(p==='low')return'🟢'; return'⚪'; }
function clip(s,n){ s=String(s||''); return s.length>n ? s.slice(0,n-1).trimEnd()+'…' : s; }

// Extrae la PWI que CAUSA este EWI (link "is caused by" -> inwardIssue del proyecto PWI).
// Replica en JS el filtro que las automatizaciones hacen con el Branch "is caused by".
function causedByPwiKey(links){
  if (!Array.isArray(links)) return null;
  for (const l of links) {
    const t = l.type || {};
    // El EWI "is caused by" la PWI: la PWI aparece como inwardIssue cuando inward = "is caused by".
    if (t.inward === 'is caused by' && l.inwardIssue) {
      const k = l.inwardIssue.key || '';
      if (k.startsWith('PWI-')) return k;
    }
    // Robustez: tambien contemplar el caso espejo (outward causes apuntando a PWI)
    if (t.outward === 'causes' && l.outwardIssue) {
      const k = l.outwardIssue.key || '';
      if (k.startsWith('PWI-')) return k;
    }
  }
  return null;
}
// ============================================================================
// BLOQUE COMÚN — Sección "Prioridades globales" (dos tablas: What's next / What's going on)
// Se inyecta en los 5 builders. Construida SIEMPRE desde el PWI. La ven TODOS los perfiles.
// Depende de: helpers table()/emptyNote() definidos en el builder.
// opts.tecnico=true agrega la columna EWI (key del espejo) en ambas tablas.
// ----------------------------------------------------------------------------
// Columnas:
//   What's next     : Rank · PWI · Requerimiento · Estado(PWI) · Prioridad · Área [· EWI]
//                     (Rank = entero consecutivo 1,2,3… según orden LexoRank del PWI)
//   What's going on : PWI · Requerimiento · Estado(EWI) · Prioridad · Área [· EWI]
//                     (Estado = estado del EWI espejo: lo más cercano a la realidad)
// ============================================================================

// Resuelve el EWI espejo válido de un PWI Requirement desde sus issuelinks.
// Validación del par: name 'Problem/Incident' + outward 'causes' + target EWI-*
// + tipo Epic/Story. Descarta Relates/Blocks, AM-* legacy y links sucios.
function espejoValido(issuelinks){
  if (!Array.isArray(issuelinks)) return null;
  for (const l of issuelinks) {
    const t = l.type || {};
    if (t.name === 'Problem/Incident' && t.outward === 'causes' && l.outwardIssue) {
      const k = l.outwardIssue.key || '';
      const ty = ((l.outwardIssue.fields || {}).issuetype || {}).name || '';
      if (k.startsWith('EWI-') && (ty === 'Epic' || ty === 'Story')) {
        const stObj = ((l.outwardIssue.fields || {}).status || {});
        const st = stObj.name || '';
        const stCat = (stObj.statusCategory || {}).key || '';
        return { key: k, type: ty, status: st, statusCategory: stCat };
      }
    }
  }
  return null;
}

function rankCmp(a, b){
  if (!a.rank && !b.rank) return 0;
  if (!a.rank) return 1;
  if (!b.rank) return -1;
  return a.rank < b.rank ? -1 : (a.rank > b.rank ? 1 : 0);
}

// Orden de fase para "What's going on" (avance del pipeline de dev del PWI).
const PWI_PHASE_ORDER = { 'SENT TO DEV':0, 'READY FOR DEV':1, 'IN DEVELOPMENT':2, 'BLOCKED':3 };
function phaseCmp(a, b){
  const pa = PWI_PHASE_ORDER[a.status] ?? 99;
  const pb = PWI_PHASE_ORDER[b.status] ?? 99;
  if (pa !== pb) return pa - pb;
  return rankCmp(a, b);
}


// Barra de progreso textual de 10 segmentos.
function progressBar(pct){
  const filled = Math.round((pct/100)*10);
  return '\u2593'.repeat(filled) + '\u2591'.repeat(10-filled) + ` ${pct}%`;
}

// Completitud de un PWI en going-on, dado su espejo y el mapa byParent.
// Regla: si el espejo Story tiene child -> done/total (mandan los child).
//        si no tiene child -> la Story es la unidad: 100 si está Done, 0 si no.
function completitud(esp, byParent){
  if (!esp) return { pct: 0, label: '\u2014' };
  const childs = (byParent && byParent[esp.key]) || [];
  if (childs.length > 0) {
    const done = childs.filter(c => c.statusCategory === 'done').length;
    const total = childs.length;
    const pct = Math.round((done/total)*100);
    return { pct, label: `${done}/${total}` };
  }
  // sin child: la Story misma
  const espDone = (esp.statusCategory || '').toLowerCase() === 'done';
  return { pct: espDone ? 100 : 0, label: '\u2014' };
}

// Construye la sección "Prioridades globales" completa (header + dos sub-tablas).
// rows: array normalizado con key, summary, status, priority, area, rank,
//       issueType, issuelinks (raw, para resolver el espejo).
function buildPrioridadesGlobales(rows, opts){
  opts = opts || {};
  const tecnico = !!opts.tecnico;
  const counts = (opts.counts && typeof opts.counts === 'object') ? opts.counts : null;
  const byParent = (opts.byParent && typeof opts.byParent === 'object') ? opts.byParent : {};

  // Solo PWI Requirement entran a la cola (perspectiva del PWI).
  const reqs = rows.filter(r => r.issueType === 'Requirement');

  const next = [], going = [];
  for (const r of reqs) {
    const esp = espejoValido(r.issuelinks);
    r._esp = esp;
    if (!esp || esp.type === 'Epic') next.push(r);  // sin espejo o en refinamiento
    else going.push(r);                              // espejo Story -> en desarrollo
  }
  next.sort(rankCmp);
  going.sort(phaseCmp);
  if (counts) { counts.next = next.length; counts.going = going.length; }

  // Header de sección que engloba las dos tablas. Los sub-títulos (con contador)
  // van en el caption de cada data_table, evitando duplicar el header. El header
  // lleva un emoji marcador + un kicker de contexto debajo para fijar la jerarquía
  // de sección frente al caption de las tablas (decisión validada en Block Kit Builder).
  const blocks = [
    { type:'header', text:{ type:'plain_text', text:':round_pushpin: Prioridades globales', emoji:true } },
    { type:'context', elements:[{ type:'mrkdwn', text:'_Cola de Producto y Tecnología · priorización y seguimiento_' }] }
  ];

  // --- What's next ---  (Rank consecutivo + Estado del PWI)
  if (next.length) {
    const headerNext = tecnico
      ? ['Rank','PWI','Requerimiento','Estado','Prioridad','Área','EWI']
      : ['Rank','PWI','Requerimiento','Estado','Prioridad','Área'];
    const rowsNext = next.map((r, i) => {
      const base = [String(i+1), r.key, r.summary, r.status, r.priority||'—', r.area||'—'];
      if (tecnico) base.push(r._esp ? r._esp.key : '—');
      return base;
    });
    blocks.push(table(`What's next? (${next.length})`, headerNext, rowsNext));
  } else {
    blocks.push(emptyNote(`*What's next? (0)* — _Sin requerimientos en cola de priorización._`));
  }

  // --- What's going on ---  (Estado del EWI espejo)
  if (going.length) {
    const headerGoing = tecnico
      ? ['PWI','Requerimiento','Estado','Avance','Prioridad','Área','EWI']
      : ['PWI','Requerimiento','Estado','Avance','Prioridad','Área'];
    const rowsGoing = going.map(r => {
      const estadoEwi = r._esp ? r._esp.status : (r.status || '—');
      const comp = completitud(r._esp, byParent);
      const avance = progressBar(comp.pct) + (comp.label !== '—' ? ` (${comp.label})` : '');
      const base = [r.key, r.summary, estadoEwi, avance, r.priority||'—', r.area||'—'];
      if (tecnico) base.push(r._esp ? r._esp.key : '—');
      return base;
    });
    blocks.push(table(`What's going on? (${going.length})`, headerGoing, rowsGoing));
  } else {
    blocks.push(emptyNote(`*What's going on? (0)* — _Nada en desarrollo ahora._`));
  }

  return blocks;
}

function row(it){
  const f = it.fields || {};
  const a = f.assignee || null;
  return {
