// ============================================================================
// miles-slack-event-router · Assemble Approval Cards
// ----------------------------------------------------------------------------
// Recibe N items que pasaron por Groq. Resumen en $json (choices...). Datos de
// la card por referencia a 'Parse Thread' (item-paired).
// Cascada: resumen Groq -> problemaParser -> '' ('abri el hilo').
// Descarta items _skip (resueltos en Slack) y approval_empty. Reinyecta byParent.
// ============================================================================

const items = $input.all();
function cleanLLM(s){ return String(s || '').replace(/^["'\s]+|["'\s]+$/g, '').trim(); }
function groqSummary(json){
  try {
    let r = json;
    if (typeof r === 'string') r = JSON.parse(r);
    if (r && r.body && !r.choices) { let b = r.body; if (typeof b === 'string') b = JSON.parse(b); r = b; }
    const c = r && r.choices && r.choices[0] && r.choices[0].message ? r.choices[0].message.content : '';
    return cleanLLM(c);
  } catch (e) { return ''; }
}

let byParent = {};
const cards = [];

for (let i = 0; i < items.length; i++) {
  let src;
  try { src = $('Parse Thread').all()[i].json; }
  catch (e) { src = items[i].json || {}; }

  if (!byParent || Object.keys(byParent).length === 0) {
    byParent = (src && src.byParent) || (items[i].json && items[i].json.byParent) || byParent;
  }

  if (src && src.approval_empty) continue;
  if (src && src._skip) continue;            // ya resuelto en Slack
  if (!src || !src.threadId) continue;

  const resumen = groqSummary(items[i].json);
  const problema = resumen || src.problemaParser || '';

  cards.push({
    threadId: src.threadId, channelId: src.channelId, requesterId: src.requesterId,
    lockedAt: src.lockedAt, problema, threadUrl: src.threadUrl, daysWaiting: src.daysWaiting,
  });
}

cards.sort((a,b) => (b.daysWaiting||0) - (a.daysWaiting||0));
return [{ json: { byParent, approval_cards: cards } }];
